const sessionId = $json.session_id;
const message = $json.message;

if (!sessionId || typeof sessionId !== 'string' || !sessionId.trim()) {
  throw new Error('session_id is required');
}

if (!message || typeof message !== 'string' || !message.trim()) {
  throw new Error('message is required');
}

return items;

const blockedPatterns = [
  'ignore previous instructions',
  'reveal system prompt',
  'act as system',
  'bypass safeguards',
  'jailbreak',
];

const message = String($json.message || '').toLowerCase();
const blocked = blockedPatterns.some((pattern) => message.includes(pattern));

if (blocked) {
  return [
    {
      json: {
        ...$json,
        response: 'Your request cannot be processed due to security restrictions.'
      }
    }
  ];
}

return items;

if ($json.response) {
  return items;
}

const emergencyPhrases = [
  'chest pain',
  "can't breathe",
  'stroke',
  'severe bleeding',
  'suicide',
  'anaphylaxis',
];

const message = String($json.message || '').toLowerCase();
const isEmergency = emergencyPhrases.some((phrase) => message.includes(phrase));

if (isEmergency) {
  return [
    {
      json: {
        ...$json,
        response: 'Your symptoms may require urgent medical attention. Call 999 immediately or contact NHS 111.'
      }
    }
  ];
}

return [
  {
    json: {
      ...$json
    }
  }
];

const fs = require('fs');
const path = require('path');

const keys = [
  'condition',
  'overview',
  'symptoms',
  'self_care',
  'when_to_see_gp',
  'when_to_call_111',
  'when_to_call_999',
];

const candidates = [
  path.resolve(process.cwd(), 'kb', 'conditions'),
  path.resolve(process.cwd(), '..', 'kb', 'conditions'),
  '/data/kb/conditions',
];

let kbDir = '';
for (const candidate of candidates) {
  if (fs.existsSync(candidate)) {
    kbDir = candidate;
    break;
  }
}

const blocks = [];

if (kbDir) {
  const files = fs.readdirSync(kbDir).filter((f) => f.toLowerCase().endsWith('.json'));

  for (const fileName of files) {
    const filePath = path.join(kbDir, fileName);
    try {
      const raw = fs.readFileSync(filePath, 'utf8');
      const data = JSON.parse(raw);

      const lines = [];
      lines.push(`Condition: ${data.condition || ''}`);
      lines.push(`Overview: ${data.overview || ''}`);
      lines.push(`Symptoms: ${Array.isArray(data.symptoms) ? data.symptoms.join(', ') : (data.symptoms || '')}`);
      lines.push(`Self Care: ${Array.isArray(data.self_care) ? data.self_care.join(', ') : (data.self_care || '')}`);
      lines.push(`When to see GP: ${data.when_to_see_gp || ''}`);
      lines.push(`When to call 111: ${data.when_to_call_111 || ''}`);
      lines.push(`When to call 999: ${data.when_to_call_999 || ''}`);

      blocks.push(lines.join('\n'));
    } catch (err) {
      continue;
    }
  }
}

const nhsContext = blocks.join('\n\n---\n\n');

return [
  {
    json: {
      ...$json,
      nhs_context: nhsContext
    }
  }
];

